#include <iostream>
#include <vector>
#include <cmath>

void drawPattern(int level, int offset) {
    if (level == 0) return;
    for (int i = 0; i < level; ++i) {
        std::cout << offset + i * 7 << " ";
    }
    std::cout << "\n";
    drawPattern(level - 1, offset + 10);
}

int main() {
    drawPattern(5, 1);
    return 0;
}
